package Day1;

public class basic10 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int i = 1;
		
			while(true) {
				i=i+1;
				System.out.println("하나씩 더해보자 " +(i));
				if (i>=10) break;
			}
			System.out.println("**************");
			
			i=0;
			while(true) {
				i=i+1;
				System.out.println("하니씩 더해보자"+(i));
				if(i>=10) break;
			}
			System.out.println("******************");
			
			i=1;
			while(true) {
				System.out.println("하나씩 더해보자 "+(i));
				i=i+1;
				if (i>=10) break;
				
			}
		}
	}
